import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }

    componentDidMount() {




      }


          render() {


            var header = "Loading ..."

            var content = []
            var items = []

            content.push(<div >
            <input type="hidden" name="todayDate" value={this.state.todayDay} />
            <input type="file" name="" id="" onChange={this.handleselectedFile} />
            <button onClick={this.handleUpload}>Upload</button>
            <br/><br/>
            <div>Upload Progress: {Math.round(this.state.loaded,2) } %</div>
            <hr></hr>
            Result:
            <div>
             {items}
            </div>
          </div>)



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Scheduler
